from pathlib import Path
from html.parser import HTMLParser

class P(HTMLParser):
    def __init__(self):
        super().__init__()
        self.in_td=False; self.in_th=False
        self.row=[]; self.rows=[]
    def handle_starttag(self, tag, attrs):
        if tag in ('td','th'):
            if tag=='td': self.in_td=True
            else: self.in_th=True
            self.row.append('')
        elif tag=='tr':
            self.row=[]
    def handle_data(self, data):
        if self.in_td or self.in_th:
            if self.row:
                self.row[-1]+=data.strip()
    def handle_endtag(self, tag):
        if tag in ('td','th'):
            if tag=='td': self.in_td=False
            else: self.in_th=False
        elif tag=='tr':
            if any(cell"'!='"'' for cell in self.row):
                self.rows.append(self.row)

text=Path('desktop/fashion_ecommerce/product_data/top10_product_status_table.xlsx').read_text(errors='ignore')
p=P(); p.feed(text)
for r in p.rows[:15]:
    print(r)
